    def test_load_action_1(self):
        action_full_json = json.loads(self.data_action_full_1())
        action_full = Action.from_ui_dict(action_full_json)
        action_json = Action.from_basic_dict(json.loads(self.data_action_basic_1()))
        self.assertEqual(action_full.to_simple_dict(), action_json.to_simple_dict())

    def test_load_action_2(self):
        action_full_json = json.loads(self.data_action_full_2())
        action_full = Action.from_ui_dict(action_full_json)
        action_json = Action.from_basic_dict(json.loads(self.data_action_basic_2()))
        self.assertEqual(action_full.to_simple_dict(), action_json.to_simple_dict())

    def test_https_redirect(self):
        action = Action(name='https-redirect', type=Action.ActionsActionTypeEnum.HTTP_REQUEST_REDIRECT,
                        http_request_redirect='scheme https')
        self.assertEqual('scheme https', action.http_request_redirect)
        self.assertEqual(Action.ActionsActionTypeEnum.HTTP_REQUEST_REDIRECT, action.type)
        self.assertEqual('https-redirect', action.name)

